using ModelContextProtocol.Server;
using System.ComponentModel;

[McpServerToolType]
public static class Tools
{
    [McpServerTool, Description("Echoes the provided message back with a timestamp.")]
    public static string Echo(
        [Description("The message to echo back")] string message)
    {
        return $"[{DateTime.UtcNow:O}] {message}";
    }

    [McpServerTool, Description("Adds two numbers and returns the result.")]
    public static string Add(
        [Description("First number")] double a,
        [Description("Second number")] double b)
    {
        return $"{a} + {b} = {a + b}";
    }
}

using ModelContextProtocol.Server;
using System.ComponentModel;
using System.Text.Json;

[McpServerResourceType]
public static class Resources
{
    [McpServerResource(UriTemplate = "config://app", Name = "App Config",
        MimeType = "application/json"),
     Description("Returns current application configuration data.")]
    public static string GetAppConfig()
    {
        var config = new
        {
            AppName = "HttpMcpServer",
            Version = "1.0.0",
            Environment = Environment.GetEnvironmentVariable("ASPNETCORE_ENVIRONMENT") ?? "Production",
            MaxRetries = 3,
            TimeoutSeconds = 30,
            Features = new { Logging = true, Caching = false }
        };

        return JsonSerializer.Serialize(config, new JsonSerializerOptions { WriteIndented = true });
    }

    [McpServerResource(UriTemplate = "config://status", Name = "Server Status",
        MimeType = "application/json"),
     Description("Returns server uptime and status information.")]
    public static string GetServerStatus()
    {
        var status = new
        {
            Status = "Healthy",
            StartedAt = Program.StartTime,
            Uptime = DateTime.UtcNow - Program.StartTime,
            MachineName = Environment.MachineName
        };

        return JsonSerializer.Serialize(status, new JsonSerializerOptions { WriteIndented = true });
    }
}

